import React from 'react';
import { useNavigate } from 'react-router-dom';

const modules = [
  {
    title: "Password Practice",
    image: "/images/simulation/1.png",
    path: "/simulation/password",
  },
  {
    title: "Social Media Practice",
    image: "/images/simulation/2.png",
    path: "/simulation/social",
  },
  {
    title: "Scam Email Practice",
    image: "/images/simulation/3.png",
    path: "/simulation/scam",
  },
  {
    title: "Text Trap Practice",
    image: "/images/simulation/4.png",
    path: "/simulation/text",
  }
];

export default function SimulationPage() {
  const navigate = useNavigate();

  return (
    <div style={styles.pageWrapper}>
      <div style={styles.container}>
        <h2 style={styles.header}>🧩 Choose a Simulation</h2>
        {modules.map((mod, idx) => (
          <div
            key={idx}
            onClick={() => navigate(mod.path)}
            style={styles.card}
          >
            <img src={mod.image} alt={mod.title} style={styles.image} />
            <div style={styles.title}>{mod.title}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  pageWrapper: {
    backgroundColor: '#fff',
    minHeight: '100vh', // ✅ 和 HomePage 保持一致
    paddingTop: '1em',  // ✅ 给导航栏下方留出空间（避免内容顶到导航栏边）
  },
  container: {
    padding: '1em',
    fontFamily: 'Arial',
    maxWidth: '500px',
    margin: '0 auto'
  },
  header: {
    textAlign: 'center',
    fontSize: '1.5em',
    marginBottom: '1em'
  },
  card: {
    backgroundColor: '#fff',
    borderRadius: '16px',
    marginBottom: '1em',
    overflow: 'hidden',
    boxShadow: '0 4px 10px rgba(0,0,0,0.1)',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    padding: '0.5em'
  },
  image: {
    width: '80px',
    height: '80px',
    borderRadius: '12px',
    objectFit: 'cover',
    marginRight: '1em'
  },
  title: {
    fontSize: '1.1em',
    fontWeight: 'bold'
  }
};
